"use strict";(self.webpackChunkdocusaurus_knowledge_base=self.webpackChunkdocusaurus_knowledge_base||[]).push([[13398],{92965(e,t,i){i.r(t),i.d(t,{assets:()=>c,contentTitle:()=>r,default:()=>d,frontMatter:()=>a,metadata:()=>o,toc:()=>h});let o=JSON.parse('{"id":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 38 Intangible Assets and IAS 2 Inventories/configuration-or-customisation-costs-acd1e0b2c4","title":"Configuration or Customisation Costs in a Cloud Computing Arrangement (IAS 38)","description":"April 2021","source":"@site/knowledge/6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 38 Intangible Assets and IAS 2 Inventories/Configuration or Customisation Costs in a Cloud Computing Arrangement (IAS 38).md","sourceDirName":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 38 Intangible Assets and IAS 2 Inventories","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-38-intangible-assets-and-ias-2-i-babc46cedc/configuration-or-customisation-costs-acd1e0b2c4","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-38-intangible-assets-and-ias-2-i-babc46cedc/configuration-or-customisation-costs-acd1e0b2c4","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":1,"frontMatter":{"id":"configuration-or-customisation-costs-acd1e0b2c4","title":"Configuration or Customisation Costs in a Cloud Computing Arrangement (IAS 38)","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-38-intangible-assets-and-ias-2-i-babc46cedc/configuration-or-customisation-costs-acd1e0b2c4","sidebar_position":1},"sidebar":"knowledgeSidebar","previous":{"title":"Player Transfer Payments (IAS 38)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-38-intangible-assets-ac4723e282/player-transfer-payments-ias-38-7cb77accfb"},"next":{"title":"Holdings of Cryptocurrencies","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-38-intangible-assets-and-ias-2-i-babc46cedc/holdings-of-cryptocurrencies-d65a896f52"}}');var s=i(74848),n=i(28453);let a={id:"configuration-or-customisation-costs-acd1e0b2c4",title:"Configuration or Customisation Costs in a Cloud Computing Arrangement (IAS 38)",slug:"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-38-intangible-assets-and-ias-2-i-babc46cedc/configuration-or-customisation-costs-acd1e0b2c4",sidebar_position:1},r="Configuration or Customisation Costs in a Cloud Computing Arrangement (IAS 38)",c={},h=[{value:"Does the customer recognise an intangible asset in relation to configuration or customisation of the application software (Question I)?",id:"does-the-customer-recognise-an-intangible-asset-in-relation-to-configuration-or-customisation-of-the-application-software-question-i",level:2},{value:"If an intangible asset is not recognised, how does the customer account for the configuration or customisation costs (Question II)?",id:"if-an-intangible-asset-is-not-recognised-how-does-the-customer-account-for-the-configuration-or-customisation-costs-question-ii",level:2}];function u(e){let t={h1:"h1",h2:"h2",header:"header",p:"p",...(0,n.R)(),...e.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsx)(t.header,{children:(0,s.jsx)(t.h1,{id:"configuration-or-customisation-costs-in-a-cloud-computing-arrangement-ias-38",children:"Configuration or Customisation Costs in a Cloud Computing Arrangement (IAS 38)"})}),"\n",(0,s.jsx)(t.p,{children:"April 2021"}),"\n",(0,s.jsx)(t.p,{children:"The Committee received a request about how a customer accounts for costs of configuring or customising a supplier\u2019s application software in a Software as a Service (SaaS) arrangement. In the fact pattern described in the request:"}),"\n",(0,s.jsx)(t.p,{children:"a. a customer enters into a SaaS arrangement with a supplier. The contract conveys to the customer the right to receive access to the supplier\u2019s application software over the contract term. That right to receive access does not provide the customer with a software asset and, therefore, the access to the software is a service that the customer receives over the contract term.\nb. the customer incurs costs of configuring or customising the supplier\u2019s application software to which the customer receives access. The request describes configuration and customisation as follows:\ni. configuration involves the setting of various \u2018flags\u2019 or \u2018switches\u2019 within the application software, or defining values or parameters, to set up the\nsoftware\u2019s existing code to function in a specified way.\nii. customisation involves modifying the software code in the application or writing additional code. Customisation generally changes, or creates\nadditional, functionalities within the software.\nc. the customer receives no other goods or services."}),"\n",(0,s.jsx)(t.p,{children:"In analysing the request, the Committee considered:"}),"\n",(0,s.jsx)(t.p,{children:"a. whether, applying IAS 38, the customer recognises an intangible asset in relation to configuration or customisation of the application software (Question I).\nb. if an intangible asset is not recognised, how the customer accounts for the configuration or customisation costs (Question II)."}),"\n",(0,s.jsx)(t.h2,{id:"does-the-customer-recognise-an-intangible-asset-in-relation-to-configuration-or-customisation-of-the-application-software-question-i",children:"Does the customer recognise an intangible asset in relation to configuration or customisation of the application software (Question I)?"}),"\n",(0,s.jsx)(t.p,{children:"Applying paragraph 18 of IAS 38, an entity recognises an item as an intangible asset when the entity demonstrates that the item meets both the definition of an intangible asset and the recognition criteria in paragraphs 21\u201323 of IAS 38. IAS 38 defines an intangible asset as \u2018an identifiable non-monetary asset without physical substance\u2019. IAS 38 notes that an asset is a resource controlled by an entity and paragraph 13 specifies that an entity controls an asset if it has \u2018the power to obtain the future economic benefits flowing from the underlying resource and to restrict the access of others to those benefits\u2019."}),"\n",(0,s.jsx)(t.p,{children:"In the fact pattern described in the request, the supplier controls the application software to which the customer has access. The assessment of whether configuration or customisation of that software results in an intangible asset for the customer depends on the nature and output of the configuration or customisation performed. The Committee observed that, in the SaaS arrangement described in the request, the customer often would not recognise an intangible asset because it does not control the software being configured or customised and those configuration or customisation activities do not create a resource controlled by the customer that is separate from the software. In some circumstances, however, the arrangement may result in, for example, additional code from which the customer has the power to obtain the future economic benefits and to restrict others\u2019 access to those benefits. In that case, in determining whether to recognise the additional code as an intangible asset, the customer assesses whether the additional code is identifiable and meets the recognition criteria in IAS 38."}),"\n",(0,s.jsx)(t.h2,{id:"if-an-intangible-asset-is-not-recognised-how-does-the-customer-account-for-the-configuration-or-customisation-costs-question-ii",children:"If an intangible asset is not recognised, how does the customer account for the configuration or customisation costs (Question II)?"}),"\n",(0,s.jsx)(t.p,{children:"If the customer does not recognise an intangible asset in relation to configuration or customisation of the application software, it applies paragraphs 68\u201370 of IAS 38 to account for those costs. The Committee observed that:"}),"\n",(0,s.jsx)(t.p,{children:"a. the customer recognises the costs as an expense when it receives the configuration or customisation services (paragraph 69). Paragraph 69A specifies that \u2018services are received when they are performed by a supplier in accordance with a contract to deliver them to the entity and not when the entity uses them to deliver another service\u2019. In assessing when to recognise the costs as an expense, IAS 38 therefore requires the customer to determine when the supplier performs the configuration or customisation services in accordance with the contract to deliver those services.\nb. IAS 38 includes no requirements that deal with the identification of the services the customer receives in determining when the supplier performs those services in accordance with the contract to deliver them. Paragraphs 10\u201311 of IAS 8 Accounting Policies, Changes in Accounting Estimates and Errors require the customer to refer to, and consider the applicability of, the requirements in IFRS Standards that deal with similar and related issues. The Committee observed that IFRS 15 Revenue from Contracts with Customers includes requirements that suppliers apply in identifying the promised goods or services in a contract with a customer. For the fact pattern described in the request, those requirements in IFRS 15 deal with issues similar and related to those faced by the customer in determining when the supplier performs the configuration or customisation services in accordance with the contract to deliver those services.\nc. if the contract to deliver the configuration or customisation services to the customer is with the supplier of the application software (including cases in which the supplier subcontracts services to a third party), the customer applies paragraphs 69\u201369A of IAS 38 and determines when the supplier of the application software performs those services in accordance with the contract to deliver them as follows:\ni. if the services the customer receives are distinct, then the customer recognises the costs as an expense when the supplier configures or customises the application software.\nii. if the services the customer receives are not distinct (because those services are not separately identifiable from the customer\u2019s right to receive access to the supplier\u2019s application software), then the customer recognises the costs as an expense when the supplier provides access to the application software over the contract term.\nd. if the contract to deliver the configuration or customisation services to the customer is with a third-party supplier, the customer applies paragraphs 69\u201369A of IAS 38 and determines when the third-party supplier performs those services in accordance with the contract to deliver them. In applying these requirements, the customer recognises the costs as an expense when the third-party supplier configures or customises the application software.\ne. if the customer pays the supplier of the configuration or customisation services before receiving those services, it recognises the prepayment as an asset (paragraph 70 of IAS 38)."}),"\n",(0,s.jsx)(t.p,{children:"Paragraphs 117\u2013124 of IAS 1 Presentation of Financial Statements require the customer to disclose its accounting policy for configuration or customisation costs when that disclosure is relevant to an understanding of its financial statements."}),"\n",(0,s.jsx)(t.p,{children:"The Committee concluded that the principles and requirements in IFRS Standards provide an adequate basis for a customer to determine its accounting for configuration or customisation costs incurred in relation to the SaaS arrangement described in the request. Consequently, the Committee decided not to add a standard-setting project to the work plan."})]})}function d(e={}){let{wrapper:t}={...(0,n.R)(),...e.components};return t?(0,s.jsx)(t,{...e,children:(0,s.jsx)(u,{...e})}):u(e)}},28453(e,t,i){i.d(t,{R:()=>a,x:()=>r});var o=i(96540);let s={},n=o.createContext(s);function a(e){let t=o.useContext(n);return o.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(s):e.components||s:a(e.components),o.createElement(n.Provider,{value:t},e.children)}}}]);